#pragma once
#include <Arduino.h>
#include <ESPAsyncWebServer.h>
#include <ArduinoJson.h>
#include <Update.h>   // OTA flash writer (#126) — esp32 core, no external lib
#include "../core/api.h"
#include "flow_sensor.h"
#include "wifi_manager.h"
#include "spa_gz.h"   // generated by tools/build_spa.py from web/index.html (#59)

// Build identity (#126): injected by tools/fw_build_id.py as the git short-sha so
// /api/status can prove which image is running (the only way to observe that an
// OTA actually took). "dev" = built outside git or with the script bypassed.
#ifndef FW_BUILD
#define FW_BUILD "dev"
#endif

// WebServer — the HTTP plumbing for the §10 API (#55/#56). All POLICY lives in
// core Api (host-tested); this file is routes, body collection, and one mutex.
//
// CONCURRENCY: ESPAsyncWebServer handlers run on the async_tcp task (core 0)
// while the cooperative loop owns core 1 — genuine parallelism, so every Api call
// (which reads/mutates RunController & co.) is serialized against the loop with
// one FreeRTOS mutex. The loop takes it for each tick body and releases between
// passes (sub-ms hold when idle), so a handler waits at most a tick or two;
// a handler that can't get it within LOCK_TIMEOUT_MS answers 503 instead of
// blocking the TCP task. The §2 budget is unaffected — an uncontended take is
// tens of cycles. KNOWN BOUND: a handler holds the mutex across its NVS writes
// (postSchedule/postSettings), and a worst-case NVS page-GC pause (~100s of ms)
// stalls the next loop pass — and the 250 ms heartbeat against the ATtiny's 2 s
// timeout — for that long. Margin today is ~10x and edits are operator-rate; if
// the margin ever tightens, defer NVS persistence to the loop side of the lock.
//
// BODY COLLECTION: POST bodies accumulate chunk-by-chunk into a malloc'd buffer
// hung on request->_tempObject (the framework free()s it with the request), then
// the whole body parses once in the final handler. Bodies above BODY_CAP answer
// 413 — the largest legitimate §10 payload (a full 16-entry schedule) is < 2 KB.

namespace tinkle {

class WebServer {
public:
    static constexpr size_t   BODY_CAP        = 4096;
    static constexpr uint32_t LOCK_TIMEOUT_MS = 250;

    WebServer(Api& api, FlowSensor& flowSensor, WifiManager& wifi)
        : server_(80), api_(api), flowSensor_(flowSensor), wifi_(wifi) {}

    void begin() {
        mutex_ = xSemaphoreCreateMutex();

        // The SPA (§10.1, #58/#59): one gzipped page out of PROGMEM. No mutex —
        // it touches no core state. no-cache + ETag: the phone revalidates each
        // load (a 304 is one round trip) so a reflash never serves a stale UI.
        server_.on("/",           HTTP_GET, [](AsyncWebServerRequest* r) { sendSpa(r); });
        server_.on("/index.html", HTTP_GET, [](AsyncWebServerRequest* r) { sendSpa(r); });

        server_.on("/api/status",   HTTP_GET, [this](AsyncWebServerRequest* r) { handleGet(r, Get::Status); });
        server_.on("/api/schedule", HTTP_GET, [this](AsyncWebServerRequest* r) { handleGet(r, Get::Schedule); });
        server_.on("/api/settings", HTTP_GET, [this](AsyncWebServerRequest* r) { handleGet(r, Get::Settings); });
        server_.on("/api/history",  HTTP_GET, [this](AsyncWebServerRequest* r) { handleGet(r, Get::History); });

        onPost("/api/run",              Post::Run);
        onPost("/api/stop",             Post::Stop);
        onPost("/api/schedule",         Post::Schedule);
        onPost("/api/settings",         Post::Settings);
        onPost("/api/calibrate/start",  Post::CalStart);
        onPost("/api/calibrate/finish", Post::CalFinish);
        onPost("/api/fault/clear",      Post::FaultClear);

        // OTA (#126): its own route, NOT onPost — the generic path buffers whole
        // bodies under BODY_CAP (4 KB), while a ~900 KB image must stream chunk-by-
        // chunk straight to Update.write(), never accumulated in RAM. The gate
        // decision (IDLE/FAULT only + the run inhibit) is core Api policy; this is
        // the plumbing. The device is already on the arduino-esp32 default dual-app
        // partition table (app0/app1 + otadata), so no partition work was needed.
        server_.on("/api/ota", HTTP_POST,
            [this](AsyncWebServerRequest* r) { otaFinish(r); },
            [this](AsyncWebServerRequest* r, const String&, size_t index,
                   uint8_t* data, size_t len, bool) { otaChunk(r, index, data, len); });

        server_.onNotFound([](AsyncWebServerRequest* r) {
            r->send(404, "application/json", "{\"error\":\"not found\"}");
        });
        server_.begin();
    }

    // The loop's side of the serialization: wrap each tick body in lock()/unlock().
    void lock()   { if (mutex_) xSemaphoreTake(mutex_, portMAX_DELAY); }
    void unlock() { if (mutex_) xSemaphoreGive(mutex_); }

    // OTA reboot seam (#126): the flash succeeded and the 200 has been queued; the
    // loop (outside its lock) calls ESP.restart() once this reads true. The delay
    // lets the TCP stack flush the response before the connection dies. Restarting
    // from the loop, not the async_tcp task, keeps teardown off the network core.
    bool restartDue(uint32_t nowMs) const {
        return restartPending_ && (int32_t)(nowMs - restartAtMs_) >= 0;
    }

private:
    enum class Get  : uint8_t { Status, Schedule, Settings, History };
    enum class Post : uint8_t { Run, Stop, Schedule, Settings, CalStart, CalFinish, FaultClear };

    void handleGet(AsyncWebServerRequest* r, Get which) {
        if (!mutex_ || xSemaphoreTake(mutex_, pdMS_TO_TICKS(LOCK_TIMEOUT_MS)) != pdTRUE) {
            r->send(503, "application/json", "{\"error\":\"busy\"}");
            return;
        }
        JsonDocument out;
        int code = 500;
        switch (which) {
            case Get::Status:
                code = api_.getStatus(out, millis());
                // ESP32-only facts the core can't know, merged into the same doc.
                {
                    JsonObject w = out["wifi"].to<JsonObject>();
                    w["mode"] = wifi_.modeName();
                    w["ip"]   = wifi_.ip();
                    w["rssi"] = wifi_.rssi();
                }
                out["uptimeMs"] = millis();
                out["build"]    = FW_BUILD;   // #126: git short-sha — proves which image runs
                break;
            case Get::Schedule: code = api_.getSchedule(out); break;
            case Get::Settings: code = api_.getSettings(out); break;
            case Get::History:  code = api_.getHistory(out, millis()); break;
        }
        xSemaphoreGive(mutex_);
        sendJson(r, code, out);
    }

    void onPost(const char* path, Post which) {
        server_.on(path, HTTP_POST,
            [this, which](AsyncWebServerRequest* r) { handlePost(r, which); },
            nullptr,
            // Chunk accumulator: one contiguous buffer, framework-freed. The bounds
            // guard doesn't trust the parser's index/len arithmetic — a future lib
            // swap must degrade to a 400, never a heap overflow.
            [](AsyncWebServerRequest* r, uint8_t* data, size_t len, size_t index, size_t total) {
                if (total > BODY_CAP) return;                  // judged in handlePost
                if (index == 0) r->_tempObject = calloc(total + 1, 1);
                if (r->_tempObject && index + len <= total)
                    memcpy((uint8_t*)r->_tempObject + index, data, len);
            });
    }

    void handlePost(AsyncWebServerRequest* r, Post which) {
        if (r->contentLength() > BODY_CAP) {
            r->send(413, "application/json", "{\"error\":\"body too large\"}");
            return;
        }
        JsonDocument in;
        if (r->_tempObject) {
            if (deserializeJson(in, (const char*)r->_tempObject) != DeserializationError::Ok) {
                r->send(400, "application/json", "{\"error\":\"malformed JSON\"}");
                return;
            }
        }

        if (!mutex_ || xSemaphoreTake(mutex_, pdMS_TO_TICKS(LOCK_TIMEOUT_MS)) != pdTRUE) {
            r->send(503, "application/json", "{\"error\":\"busy\"}");
            return;
        }
        const uint32_t now    = millis();
        const uint32_t pulses = flowSensor_.pulses();
        JsonDocument out;
        JsonVariantConst body = in.as<JsonVariantConst>();
        int code = 500;
        switch (which) {
            case Post::Run:        code = api_.postRun(body, out, now);                   break;
            case Post::Stop:       code = api_.postStop(out, now);                        break;
            case Post::Schedule:   code = api_.postSchedule(body, out, now);              break;
            case Post::Settings:   code = api_.postSettings(body, out, now);              break;
            case Post::CalStart:   code = api_.postCalStart(body, out, pulses, now);      break;
            case Post::CalFinish:  code = api_.postCalFinish(body, out, pulses, now);     break;
            case Post::FaultClear: code = api_.postFaultClear(out, now);                  break;
        }
        xSemaphoreGive(mutex_);
        sendJson(r, code, out);
    }

    // --- OTA upload (#126) ---------------------------------------------------
    // Runs on the async_tcp task. Per-upload state lives in members: the SPA is a
    // single-operator surface, and postOtaBegin 409s a second concurrent begin
    // anyway (the inhibit is already set), so one in-flight upload is structural.

    void otaChunk(AsyncWebServerRequest* r, size_t index, uint8_t* data, size_t len) {
        if (index == 0) {
            otaRejectCode_ = 0;
            otaBegun_      = false;
#ifdef OTA_SECRET
            // Build-time shared secret (untracked ota_secret.ini) — anyone on the
            // LAN can reach this route, and it swaps the firmware. DEC-019 keeps
            // the threat model at "already on the farm Wi-Fi", so a header key is
            // proportionate; without the ini the build runs key-less.
            if (!r->hasHeader("X-OTA-Key") ||
                r->getHeader("X-OTA-Key")->value() != OTA_SECRET) {
                otaRejectCode_ = 401;
                return;
            }
#endif
            if (!mutex_ || xSemaphoreTake(mutex_, pdMS_TO_TICKS(LOCK_TIMEOUT_MS)) != pdTRUE) {
                otaRejectCode_ = 503;
                return;
            }
            JsonDocument gateOut;
            const int code = api_.postOtaBegin(gateOut, millis());   // sets the run inhibit
            xSemaphoreGive(mutex_);
            if (code != 200) { otaRejectCode_ = code; return; }
            if (!Update.begin(UPDATE_SIZE_UNKNOWN)) {
                otaLiftInhibit();
                otaRejectCode_ = 500;
                return;
            }
            otaBegun_ = true;
            // A dropped connection mid-upload never reaches otaFinish — without
            // this, the run inhibit would stay latched until a power cycle.
            r->onDisconnect([this]() {
                if (otaBegun_) {
                    Update.abort();
                    otaLiftInhibit();
                    otaBegun_ = false;
                }
            });
        }
        if (otaRejectCode_ || !otaBegun_) return;   // rejected: drain the stream silently
        if (Update.write(data, len) != len) {
            Update.abort();
            otaLiftInhibit();
            otaBegun_      = false;
            otaRejectCode_ = 500;
        }
    }

    void otaFinish(AsyncWebServerRequest* r) {
        if (otaRejectCode_) {
            const char* msg = otaRejectCode_ == 401 ? "bad OTA key"
                            : otaRejectCode_ == 409 ? "run active or queued — OTA refused"
                            : otaRejectCode_ == 503 ? "busy"
                                                    : "flash write failed";
            JsonDocument out;
            out["error"] = msg;
            sendJson(r, (int)otaRejectCode_, out);
            return;
        }
        if (!otaBegun_) {
            r->send(400, "application/json", "{\"error\":\"no image uploaded\"}");
            return;
        }
        // end(true) validates the image (magic byte + checksum) BEFORE flipping
        // otadata — a truncated/corrupt upload never becomes the boot target; the
        // old slot keeps booting. That, not bootloader rollback (absent from the
        // stock arduino-esp32 bootloader), is the recoverability story.
        if (Update.end(true)) {
            otaBegun_       = false;
            restartAtMs_    = millis() + RESTART_DELAY_MS;
            restartPending_ = true;   // inhibit stays set — nothing may run pre-reboot
            r->send(200, "application/json", "{\"flashed\":true,\"rebooting\":true}");
        } else {
            otaLiftInhibit();
            otaBegun_ = false;
            r->send(500, "application/json", "{\"error\":\"image invalid or incomplete\"}");
        }
    }

    // Clear the run inhibit after a failed upload. Prefer the mutex; on a timeout
    // fall back to the bare call — it's a single aligned bool store (volatile in
    // RunController), and staying latched would brick scheduling until reboot.
    void otaLiftInhibit() {
        if (mutex_ && xSemaphoreTake(mutex_, pdMS_TO_TICKS(LOCK_TIMEOUT_MS)) == pdTRUE) {
            api_.otaAbort();
            xSemaphoreGive(mutex_);
        } else {
            api_.otaAbort();
        }
    }

    static void sendSpa(AsyncWebServerRequest* r) {
        if (r->hasHeader("If-None-Match") &&
            r->getHeader("If-None-Match")->value() == SPA_ETAG) {
            r->send(304);
            return;
        }
        AsyncWebServerResponse* res =
            r->beginResponse_P(200, "text/html", SPA_GZ, SPA_GZ_LEN);
        res->addHeader("Content-Encoding", "gzip");
        res->addHeader("ETag", SPA_ETAG);
        res->addHeader("Cache-Control", "no-cache");
        r->send(res);
    }

    static void sendJson(AsyncWebServerRequest* r, int code, const JsonDocument& doc) {
        String payload;
        serializeJson(doc, payload);
        if (payload.length() == 0) payload = "{}";
        r->send(code, "application/json", payload);
    }

    static constexpr uint32_t RESTART_DELAY_MS = 750;   // let the 200 flush first

    AsyncWebServer    server_;
    Api&              api_;
    FlowSensor&       flowSensor_;
    WifiManager&      wifi_;
    SemaphoreHandle_t mutex_ = nullptr;

    // OTA state (#126) — written on async_tcp, read by the loop (restartDue).
    volatile bool     restartPending_ = false;
    volatile uint32_t restartAtMs_    = 0;
    volatile uint16_t otaRejectCode_  = 0;      // non-zero = this upload was refused
    volatile bool     otaBegun_       = false;  // Update.begin() succeeded
};

} // namespace tinkle
